class Solution:
    def maxSum(self, nums, k, m):
        n = len(nums)
        best = [float('-inf')]

        def rec(idx, remaining_k, cur_sum):
            if remaining_k == 0:
                if cur_sum > best[0]:
                    best[0] = cur_sum
                return
            if idx >= n:
                return
            rec(idx + 1, remaining_k, cur_sum)
            for length in range(m, n - idx + 1):
                rec(idx + length, remaining_k - 1, cur_sum + sum(nums[idx:idx + length]))

        rec(0, k, 0)
        return best[0]

