class Solution:
    def maxSum(self, nums, k, m):
        n = len(nums)
        NEG = float('-inf')
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        dp_prev = [0] * (n + 1)
        for j in range(1, k + 1):
            dp_cur = [NEG] * (n + 1)
            running_best = NEG
            for i in range(1, n + 1):
                cand_start = i - m
                if cand_start >= 0 and dp_prev[cand_start] > NEG:
                    val = dp_prev[cand_start] - prefix[cand_start]
                    if val > running_best:
                        running_best = val
                dp_cur[i] = dp_cur[i - 1]
                if running_best > NEG and running_best + prefix[i] > dp_cur[i]:
                    dp_cur[i] = running_best + prefix[i]
            dp_prev = dp_cur
        return dp_prev[n]

