var maxSum = function(nums, k, m) {
    const n = nums.length;
    const NEG = -Infinity;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + nums[i];
    let dpPrev = new Array(n + 1).fill(0);
    for (let j = 1; j <= k; j++) {
        const dpCur = new Array(n + 1).fill(NEG);
        let runningBest = NEG;
        for (let i = 1; i <= n; i++) {
            const candStart = i - m;
            if (candStart >= 0 && dpPrev[candStart] > NEG) {
                const val = dpPrev[candStart] - prefix[candStart];
                if (val > runningBest) runningBest = val;
            }
            dpCur[i] = dpCur[i - 1];
            if (runningBest > NEG && runningBest + prefix[i] > dpCur[i]) {
                dpCur[i] = runningBest + prefix[i];
            }
        }
        dpPrev = dpCur;
    }
    return dpPrev[n];
};
